#include<bits/stdc++.h>
using namespace std;
int main() {
	int n,a[100001]={0},x,ans=0;
    cin>>n;
    for(int i=0;i<n;i++){
        cin>>x;
        a[x]=1;
    }
    for(int i=0;i<100001;i++){
        if(a[i]==1){
            ans++;
        }
    }
    cout<<ans<<'\n';
    for(int i=0;i<100001;i++){
        if(a[i]==1){
            cout<<i<<' ';
        }
    }
    return 0;
}
